filepath = "/app/src/shared/auth/dependencies.py"
with open(filepath, "r") as f:
    content = f.read()

if "verify_aud" in content and "RS256" in content:
    print("Already patched")
    exit(0)

old = """        payload = jwt.decode(
            token,
            settings.JWT_SECRET_KEY,
            algorithms=[settings.JWT_ALGORITHM],
            audience=\"flowmaster-api\",
            options={\"verify_aud\": True}
        )"""

new = """        # Support RS256 (auth-service) and HS256 (legacy)
        if settings.JWT_ALGORITHM == 'RS256':
            payload = jwt.decode(token, settings.JWT_SECRET_KEY, algorithms=[settings.JWT_ALGORITHM], options={'verify_aud': False})
        else:
            payload = jwt.decode(token, settings.JWT_SECRET_KEY, algorithms=[settings.JWT_ALGORITHM], audience=\"flowmaster-api\", options={\"verify_aud\": True})"""

if old in content:
    content = content.replace(old, new)
    with open(filepath, "w") as f:
        f.write(content)
    print("Patched OK")
else:
    print("Pattern not found - showing relevant lines:")
    for i, l in enumerate(content.split(chr(10))):
        if "jwt.decode" in l or "audience" in l or "verify_aud" in l:
            print(f"{i}: {l}")

